<!doctype html><html><head><meta charset="utf-8"><title><?= e($q['quotation_number']) ?></title><link rel="stylesheet" href="/assets/app.css"></head><body class="print"><section class="paper"><h1><?= e($company['company_name'] ?? 'Shree Axar Furniture') ?></h1><p><?= e($company['address_line_1'] ?? '') ?> <?= e($company['address_line_2'] ?? '') ?> | GST: <?= e($company['gst_number'] ?? '') ?></p><hr><h2>Quotation <?= e($q['quotation_number']) ?></h2><p><strong>Customer:</strong> <?= e($q['company_name']) ?> | <strong>Date:</strong> <?= e($q['quotation_date']) ?> | <strong>Valid:</strong> <?= e($q['valid_till']) ?></p><table><tr><th>#</th><th>Description</th><th>Qty</th><th>Rate</th><th>Discount</th><th>Tax</th><th>Total</th></tr><?php foreach($items as $i=>$it): ?><tr><td><?= $i+1 ?></td><td><?= e($it['description']) ?></td><td><?= e($it['quantity']) ?></td><td><?= money($it['rate']) ?></td><td><?= money($it['discount_amount']) ?></td><td><?= money($it['tax_amount']) ?></td><td><?= money($it['line_total']) ?></td></tr><?php endforeach; ?></table><div class="totals"><p>Subtotal: ₹<?= money($q['sub_total']) ?></p><p>Discount: ₹<?= money($q['item_discount_total'] + $q['global_discount_amount']) ?></p><p>Tax: ₹<?= money($q['tax_total']) ?></p><h2>Grand Total: ₹<?= money($q['grand_total']) ?></h2></div><h3>Terms</h3><p><?= nl2br(e($q['terms_conditions'])) ?></p><button onclick="window.print()">Print / Save PDF</button></section></body></html>
